#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e5+5;
int sum[MAXN][2],n,m,ans=0,a[MAXN];
void fix(int x,int k,int num)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		sum[i][num]^=k;
	}
}
int get_sum(int x,int num)
{
	int s=0;
	for(int i=x;i;i-=lowbit(i))
	{
		s^=sum[i][num];
	}
	return s;
}
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
    n=read(),m=read();
    FOR(i,1,n)
    {
		a[i]=read();
		fix(i,a[i],i%2); 
	}
	FOR(i,1,m)
	{
		int cmd=read(),x=read(),y=read();
		if(cmd==1)
		{
			fix(x,a[x]^y,x%2);
			a[x]=y;
		}
		else
		{
			if((x^y)%2)
			{
				puts("0"); 
				continue;
			}
			writeln(get_sum(x-1,x%2)^get_sum(y,x%2));
		}
	}
	return false;
}
